solutions.javascript:
// Solution
function solve(sql) {
  const tables = sql.split(',');
  const result = {};
  for (const table of tables) {
    const columns = db.query(`SELECT * FROM ${table}`);
    result[table] = columns.length;
  }
  return Object.keys(result).map(table => [table, result[table]]);
}

